import json

# Load all articles from the file
all_articles_file_path = locals()['var_functions.query_db:50']

# Read all articles from the file
with open(all_articles_file_path, 'r') as f:
    articles = json.load(f)

# Sports classification with better filtering
sports_keywords = {
    'specific_sports': ['football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 
                       'hockey', 'rugby', 'cricket', 'volleyball', 'bowling', 'boxing'],
    'olympic_terms': ['olympics', 'olympic', 'athlete', 'athletes', 'medal', 'championship'],
    'league_terms': ['nba', 'nfl', 'mlb', 'nhl', 'fifa', 'uefa', 'ncaa'],
    'team_terms': ['team', 'player', 'coach', 'league', 'game', 'match', 'season', 'playoff']
}

# False positive patterns to exclude
false_positives = [
    'video game', 'computer game', 'games', 'gaming',
    'windows', 'unix', 'microsoft', 'software', 'program',
    'rocket', 'space', 'satellite', 'nasa', 'launch',
    'project team', 'business team', 'engineering team',
    'band', 'music', 'recording', 'album'
]

def is_sports_article(article):
    title = article.get('title', '').lower()
    description = article.get('description', '').lower()
    text = title + ' ' + description

    # Check for false positives first
    for fp in false_positives:
        if fp in text:
            # But allow if it's clearly about sports
            if any(sport in text for sport in ['football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf']):
                return True
            return False

    # Check professional leagues
    for league in sports_keywords['league_terms']:
        if league in text:
            return True

    # Check specific sports
    for sport in sports_keywords['specific_sports']:
        if sport in text:
            return True

    # Check Olympic terms
    for term in sports_keywords['olympic_terms']:
        if term in text:
            return True

    # Check team terms (need stronger verification)
    team_indicators = ['team', 'player', 'coach', 'league']
    sport_context = ['football', 'basketball', 'baseball', 'soccer', 'hockey', 'game', 'match', 'season']

    for team_term in team_indicators:
        if team_term in text:
            # Need at least one sport context word
            if any(context in text for context in sport_context):
                return True

    return False

# Find sports article with longest description
max_desc_length = -1
sports_article_longest = None
total_sports = 0

for article in articles:
    if is_sports_article(article):
        total_sports += 1
        desc = article.get('description', '')
        desc_length = len(desc)

        if desc_length > max_desc_length:
            max_desc_length = desc_length
            sports_article_longest = {
                'title': article.get('title'),
                'article_id': article.get('article_id'),
                'description_length': desc_length
            }

print('__RESULT__:')
print(json.dumps({
    'total_articles_processed': len(articles),
    'sports_articles_found': total_sports,
    'article_with_longest_description': sports_article_longest
}))

