import json

# Load all articles from the file
all_articles_file = locals()['var_functions.query_db:68']

# Read all articles from the file
with open(all_articles_file, 'r') as f:
    articles = json.load(f)

# Comprehensive sports classification with better filtering
sports_indicators = {
    'specific_sports': ['football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf', 
                       'hockey', 'rugby', 'cricket', 'volleyball', 'bowling', 'boxing',
                       'wrestling', 'swimming', 'running', 'marathon'],
    'leagues': ['nba', 'nfl', 'mlb', 'nhl', 'fifa', 'uefa', 'ncaa'],
    'olympic_terms': ['olympics', 'olympic', 'athlete', 'athletes', 'medal', 'championship', 'tournament'],
    'team_context': ['team', 'coach', 'player', 'league', 'season', 'playoff', 'game', 'match']
}

# False positive patterns to exclude
false_positives = {
    'tech': ['windows', 'unix', 'microsoft', 'software', 'computer', 'program'],
    'gaming': ['video game', 'gaming', 'simcity'],  # Note: sports video games are ok
    'space': ['rocket', 'satellite', 'nasa', 'space'],
    'music': ['band', 'album', 'recording', 'music'],
    'business': ['project team', 'management team', 'business team']
}

# Allow these patterns even if they match false positives
allowed_patterns = ['madden nfl', 'football simulation', 'espn football']

def is_sports_article(title, description):
    """Determine if article is about sports"""
    title_lower = title.lower() if title else ''
    desc_lower = description.lower() if description else ''
    full_text = title_lower + ' ' + desc_lower

    # Check allowed patterns first
    for pattern in allowed_patterns:
        if pattern in full_text:
            return True

    # Check for false positives
    for category, terms in false_positives.items():
        for term in terms:
            if term in full_text:
                # Special exceptions for sports video games
                if term in ['gaming', 'simulation'] and ('football' in full_text or 'madden' in full_text):
                    continue
                return False

    # Check for sports leagues
    for league in sports_indicators['leagues']:
        if league in full_text:
            return True

    # Check for specific sports
    for sport in sports_indicators['specific_sports']:
        if sport in full_text:
            return True

    # Check for Olympic/sports events
    for term in sports_indicators['olympic_terms']:
        if term in full_text:
            # Exclude space/technology contexts
            if not any(space_term in full_text for space_term in ['rocket', 'satellite', 'space', 'software']):
                return True

    # Check team context with sports indicators
    has_team_context = any(team_term in full_text for team_term in sports_indicators['team_context'])
    has_sport = any(sport in full_text for sport in sports_indicators['specific_sports'] + sports_indicators['leagues'])

    if has_team_context and has_sport:
        return True

    return False

# Find sports articles with longest descriptions
sports_articles = []
max_desc_length = -1
longest_article = None

for article in articles:
    title = article.get('title', '')
    description = article.get('description', '')

    if is_sports_article(title, description):
        desc_length = len(description)

        sports_articles.append({
            'title': title,
            'article_id': article.get('article_id'),
            'desc_length': desc_length
        })

        if desc_length > max_desc_length:
            max_desc_length = desc_length
            longest_article = {
                'title': title,
                'article_id': article.get('article_id'),
                'description_length': desc_length
            }

# Sort by description length to see top articles
top_sports_articles = sorted(sports_articles, key=lambda x: x['desc_length'], reverse=True)[:10]

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(articles),
    'sports_articles_found': len(sports_articles),
    'article_with_longest_description': longest_article,
    'top_10_longest_sports_articles': top_sports_articles
}))

